section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/finops-agentic-workflow.json",
  "title": "Agentic FinOps Workflow with AI Agents",
  "type": "object",
  "required": [
    "agents",
    "approval_channel",
    "action_budgets",
    "evidence_store",
    "scope",
    "owner",
    "last_reviewed"
  ],
  "properties": {
    "agents": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "name",
          "role",
          "schedule",
          "iam_role_arn",
          "actions"
        ]
      }
    },
    "approval_channel": {
      "type": "object",
      "required": [
        "channel",
        "approver_registry_ref"
      ]
    },
    "action_budgets": {
      "type": "object",
      "required": [
        "per_hour",
        "per_day"
      ]
    },
    "evidence_store": {
      "type": "object",
      "required": [
        "target",
        "retention_days"
      ]
    },
    "scope": {
      "type": "object",
      "required": [
        "accounts",
        "environments"
      ]
    },
    "owner": {
      "type": "string"
    },
    "last_reviewed": {
      "type": "string"
    }
  },
  "additionalProperties": false
}
